function answer(question):
    messages = [system_prompt, user(question)]
    for step in 1..MAX_STEPS:
        reply = llm.generate(
            messages=messages,
            tools=[retrieve_vector, retrieve_graph, retrieve_web],
        )
        messages.append(reply)

        if not reply.tool_calls:
            return reply.content              # agent answered

        for call in reply.tool_calls:
            evidence = dispatch(call.name, call.args)
            messages.append(tool_result(call.id, evidence))
        # next iteration: agent sees evidence and either answers,
        # reformulates the query, or picks a different retriever.

    return abort("step budget exhausted")     # bounded by MAX_STEPS

# Compose CDC-vector-sync with streaming-feature-pipeline: CDC events
# feed a typed multi-stage stream. Each stage is a map with one input
# and one output schema; failures isolate per event into a dead-letter
# topic tagged with the stage they died at.

schema RawCDC:           {doc_id, op, body, version, ts}
schema CleanedDocument:  {doc_id, version, text, lang}
schema ChunkedDocument:  {chunk_id, doc_id, version, ord, text}
schema EmbeddedChunk:    {chunk_id, doc_id, version, ord, text, vec}

def stage_clean(raw: RawCDC) -> CleanedDocument:
    return CleanedDocument(
        doc_id=raw.doc_id, version=raw.version,
        text=normalise(raw.body.text),
        lang=detect_lang(raw.body.text),
    )

def stage_chunk(d: CleanedDocument) -> list[ChunkedDocument]:
    return [ChunkedDocument(chunk_id=uuid(), doc_id=d.doc_id,
                              version=d.version, ord=i, text=t)
            for i, t in enumerate(split(d.text))]

def stage_embed(c: ChunkedDocument) -> EmbeddedChunk:
    v = embed(c.text)
    return EmbeddedChunk(**c.fields, vec=v)

def pipeline():
    for raw in stream.consume("docs.cdc"):
        if raw.op == "delete":
            for chunk_id in vector_index.chunks_of(raw.doc_id):
                vector_index.delete(chunk_id)
            continue

        try:
            validated = validate(raw, RawCDC)
            cleaned   = stage_clean(validated)
            stream.emit("docs.cleaned", cleaned)         # observable stage
            for chunk in stage_chunk(cleaned):
                emb = stage_embed(chunk)
                stream.emit("docs.embedded", emb)
                vector_index.upsert(emb.chunk_id, emb.vec, meta={
                    "doc_id":  emb.doc_id,
                    "version": emb.version,
                    "ord":     emb.ord,
                })
        except ValidationError as e:
            dead_letter.publish({"event": raw, "stage": "validate",
                                   "error": str(e)})
        except StageError as e:
            dead_letter.publish({"event": raw, "stage": e.stage,
                                   "error": str(e)})

