# entire graph from scratch every refresh. Treating the graph as durable
# KG-memory lets new documents fold in incrementally and limits the
# expensive summarisation step to communities that actually changed.
# Related: see `knowledge-graph-memory`, `world-model-graph-memory`, `cdc-vector-sync`.

# Offline: build the artificial hippocampal index
function build_kg(corpus):
    graph = empty_graph()
    for passage in corpus:
        triples = llm.extract_triples(passage)            # (s, p, o) triples
        for (s, p, o) in triples:
            graph.add_node(s, passages=[passage.id])
            graph.add_node(o, passages=[passage.id])
            graph.add_edge(s, o, predicate=p)
    return graph

# Online: single-pass multi-hop retrieval
function hippocampus_retrieve(query, graph, k=10):
    concepts = llm.extract_query_concepts(query)          # seed nodes
    seeds    = { n: 1.0 for n in concepts if n in graph } # personalisation

    # Personalized PageRank propagates mass through entity edges
    scores = personalized_pagerank(graph, seeds=seeds, alpha=0.5)

    # Aggregate node mass back to source passages
    passage_scores = {}
    for node, mass in scores.items():
        for pid in graph.node(node).passages:
            passage_scores[pid] = passage_scores.get(pid, 0) + mass

    return top_k(passage_scores, k)

