# Why this works: the graph already encodes the entity bridges, so a
# single PPR pass replaces an iterative agentic loop and surfaces a
# tight path between concepts the query never explicitly mentioned.
# Related: see `hierarchical-retrieval`, `cdc-vector-sync`.

function hybrid_search(query, k=10):
    bm25_hits  = bm25_index.search(query, k=k)
    dense_hits = vector_index.search(embed(query), k=k)

    # Reciprocal Rank Fusion — rank-based, scale-free
    scores = {}
    C = 60                                                # standard RRF constant
    for rank, doc in enumerate(bm25_hits):
        scores[doc.id] = scores.get(doc.id, 0) + 1 / (C + rank)
    for rank, doc in enumerate(dense_hits):
        scores[doc.id] = scores.get(doc.id, 0) + 1 / (C + rank)

    fused = sort_desc(scores.items(), by=value)
    return [docs[doc_id] for doc_id, _ in fused[:k]]

