function multi_query_retrieve(query, n=4, k=10):
    variants = llm.generate_variants(query, n=n)         # paraphrase / decompose / step-back
    variants = [query] + variants                        # keep the original

    rankings = []
    for v in variants:
        rankings.append(retriever.search(v, k=k))        # parallel

    # Reciprocal Rank Fusion across variant rankings
    C = 60
    scores = {}
    for ranking in rankings:
        for rank, doc in enumerate(ranking):
            scores[doc.id] = scores.get(doc.id, 0) + 1 / (C + rank)

    fused = sort_desc(scores.items(), by=value)
    return [docs[doc_id] for doc_id, _ in fused[:k]]

# Self-RAG inference loop (the model has been fine-tuned to emit
# reflection tokens; the host reads them and dispatches accordingly).

function self_rag_answer(question):
    state = { "messages": [user(question)], "output": [] }

    while True:
        tok = model.generate_one_token(state.messages)

        if tok == "[Retrieve=Yes]":
            chunks = retrieve(state.current_query())
            for c in chunks:
                # ask the model to label relevance for each chunk
                rel = model.generate(state.messages + [c.as_context()])
                if rel == "[IsRel=Relevant]":
                    draft = model.generate_until(["[IsSup", "</s>"],
                                                 state.messages + [c.as_context()])
                    sup  = model.generate(draft + ["[IsSup?"])
                    use  = model.generate(draft + ["[IsUse?"])
                    state.output.append((draft, c, sup, use))
            best = argmax(state.output, by=lambda o: score(o.sup, o.use))
            return best.draft

        if tok == "[Retrieve=No]":
            return model.generate_until_stop(state.messages)

        state.messages.append(tok)

# Production Self-RAG: enforce the reflection-token grammar via structured
# decoding, cache retrievals across reflection cycles, regenerate when
# IsSup is low, and escalate when no candidate clears both IsSup and IsUse.

SUP_FLOOR        = 0.80
USE_FLOOR        = 0.70
MAX_CANDIDATES   = 5
MAX_REGENERATE   = 2

def self_rag_answer(question):
    retrieval_cache = {}
    candidates = []

    state = {"messages": [user(question)]}
    decision_tok = model.generate_one_token(
        state["messages"],
        grammar="[Retrieve=Yes]|[Retrieve=No]",
    )

    if decision_tok == "[Retrieve=No]":
        return {"answer": model.generate_until_stop(state["messages"]),
                "path": "no_retrieval"}

    # Retrieval gated. Use cache to deduplicate repeat sub-queries.
    sub_q = state_sub_query(state)
    if sub_q not in retrieval_cache:
        retrieval_cache[sub_q] = retrieve(sub_q, k=8)
    chunks = retrieval_cache[sub_q]

    for c in chunks[:MAX_CANDIDATES]:
        rel = model.generate(
            state["messages"] + [c.as_context()],
            grammar="[IsRel=Relevant]|[IsRel=Irrelevant]",
        )
        if rel != "[IsRel=Relevant]":
            metrics.inc("self_rag.skipped_irrelevant")
            continue

        draft = None
        sup_score, use_score = 0.0, 0.0
        for r in range(MAX_REGENERATE + 1):
            draft = model.generate_until(["[IsSup", "</s>"],
                                            state["messages"] + [c.as_context()])
            sup_score = parse_score(model.generate(draft + ["[IsSup?"]))
            use_score = parse_score(model.generate(draft + ["[IsUse?"]))
            if sup_score >= SUP_FLOOR:
                break
            metrics.inc("self_rag.regenerate_low_sup")

        if sup_score >= SUP_FLOOR and use_score >= USE_FLOOR:
            candidates.append({"draft": draft, "chunk": c,
                                "sup": sup_score, "use": use_score})

    if not candidates:
        return escalate(question, reason="no_supported_candidate")

    best = max(candidates, key=lambda x: x["sup"] * x["use"])
    return {"answer": best["draft"], "chunk": best["chunk"],
            "sup": best["sup"], "use": best["use"]}

# Why this works: enforcing the reflection grammar via structured decoding
# stops the model from emitting malformed tokens; the retrieval cache
# absorbs repeat sub-queries within a single answer; regeneration on low
# IsSup gives ungrounded drafts a chance to be re-grounded before they
# count against the candidate pool.
# Related: see `agentic-rag`, `reflection`, `naive-rag`.

