# Why this works: one typed model per stage pins the shape at each
# boundary, so a chunking or schema change fails loudly at the bad
# stage instead of silently corrupting the index downstream.
# Related: see `cdc-vector-sync`, `modular-rag`.

# Production streaming pipeline: bounded queues for backpressure, stage-
# tagged dead-letter, batched embedding, idempotency keys for safe replay,
# and per-stage SLO metrics.

QUEUE_BOUNDS = {"clean": 1_000, "chunk": 5_000, "embed": 500}
BATCH_SIZE   = 32

schema RawDocument:      {id, source, text, fetched_at, idem_key}
schema CleanedDocument:  {id, idem_key, source, text, lang}
schema ChunkedDocument:  {id, parent_id, idem_key, ord, text}
schema EmbeddedDocument: {id, parent_id, idem_key, ord, text, vec}

clean_q  = BoundedQueue(QUEUE_BOUNDS["clean"])
chunk_q  = BoundedQueue(QUEUE_BOUNDS["chunk"])
embed_q  = BoundedQueue(QUEUE_BOUNDS["embed"])
dlq      = queue("docs.dlq")

def stage_clean_worker():
    for raw in stream.consume("docs.cdc"):
        try:
            r = validate(raw, RawDocument)
            cleaned = CleanedDocument(
                id=r.id, idem_key=r.idem_key, source=r.source,
                text=normalise(r.text), lang=detect_lang(r.text),
            )
            clean_q.put(cleaned)        # blocks on backpressure
            metrics.observe("stage.clean.ok", 1)
        except Exception as e:
            dlq.publish({"event": raw, "stage": "clean", "error": str(e)})
            metrics.inc("stage.clean.err")

def stage_chunk_worker():
    for cleaned in clean_q:
        for i, t in enumerate(split(cleaned.text)):
            chunk_q.put(ChunkedDocument(
                id=det_uuid(cleaned.idem_key, i),    # idempotent id
                parent_id=cleaned.id, idem_key=cleaned.idem_key,
                ord=i, text=t,
            ))

def stage_embed_worker():
    batch = []
    while True:
        c = chunk_q.get(timeout="100ms")
        if c is not None:
            batch.append(c)
        if len(batch) >= BATCH_SIZE or (batch and c is None):
            vecs = embed_batch([b.text for b in batch])
            for b, v in zip(batch, vecs):
                emb = EmbeddedDocument(**b.fields, vec=v)
                # Idempotent upsert — safe on replay.
                vector_index.upsert(emb.id, emb.vec, meta=emb,
                                     idem_key=emb.idem_key)
                metrics.observe("stage.embed.ok", 1)
            batch = []

# Per-stage SLOs: queue depth and end-to-end lag.
for name, q in [("clean", clean_q), ("chunk", chunk_q), ("embed", embed_q)]:
    alert(f"stage.{name}.queue_depth",
           threshold=int(QUEUE_BOUNDS[name] * 0.8))
alert("pipeline.end_to_end_lag_ms", threshold=30_000)

