# Compose streaming-feature-pipeline with cdc-vector-sync: the stream
# source is explicitly CDC events from the source-of-truth store, doc
# version flows through every typed stage, and the index write is
# version-aware so out-of-order events cannot overwrite newer state.

schema CDCEvent:          {doc_id, op, body, version, ts}
schema CleanedDocument:   {doc_id, version, text, lang}
schema ChunkedDocument:   {chunk_id, doc_id, version, ord, text}
schema EmbeddedChunk:     {chunk_id, doc_id, version, ord, text, vec}

def on_source_change(change):
    queue.publish(topic="docs.cdc", event=CDCEvent(
        doc_id=change.doc_id, op=change.op,
        body=change.after, version=change.version, ts=now(),
    ))

def stage_clean(evt: CDCEvent) -> CleanedDocument:
    return CleanedDocument(
        doc_id=evt.doc_id, version=evt.version,
        text=normalise(evt.body.text),
        lang=detect_lang(evt.body.text),
    )

def stage_chunk(d: CleanedDocument) -> list[ChunkedDocument]:
    # Deterministic chunk ids on (doc_id, version, ord) so replays are
    # idempotent and version is part of the natural key.
    return [ChunkedDocument(
                chunk_id=det_uuid(d.doc_id, d.version, i),
                doc_id=d.doc_id, version=d.version, ord=i, text=t)
            for i, t in enumerate(split(d.text))]

def stage_embed(c: ChunkedDocument) -> EmbeddedChunk:
    return EmbeddedChunk(**c.fields, vec=embed(c.text))

def pipeline():
    for raw in stream.consume("docs.cdc"):
        try:
            evt = validate(raw, CDCEvent)

            if evt.op == "delete":
                for chunk_id in vector_index.chunks_of(evt.doc_id):
                    vector_index.delete(chunk_id)
                continue

            cleaned = stage_clean(evt)
            for chunk in stage_chunk(cleaned):
                emb = stage_embed(chunk)

                # Version-aware upsert: only write if this version is
                # newer than what is in the index for the same chunk.
                existing = vector_index.get_meta(emb.chunk_id)
                if existing and existing["version"] >= emb.version:
                    metrics.inc("pipeline.stale_drop")
                    continue
                vector_index.upsert(emb.chunk_id, emb.vec, meta={
                    "doc_id": emb.doc_id, "version": emb.version,
                    "ord":    emb.ord,
                })
        except (ValidationError, StageError) as e:
            dead_letter.publish({"event": raw, "error": str(e)})

def answer(query):
    docs     = retriever.search(query, k=10)
    reranked = reranker.rerank(query, docs)
    return llm.generate(prompt=query, context=reranked[:4])

# Why this works: pure streaming pipelines describe stages but not where
# events come from; composing with CDC nails down the source as the
# source-of-truth store and propagates document version through every
# typed stage, so out-of-order delivery (the normal case for queues)
# can never silently overwrite the index with stale data.
# Related: see `cdc-vector-sync`, `fti-llm-pipeline-split`.
